  1→import type { FastifyInstance } from 'fastify';
  2→import { parseEventLogs } from 'viem';
  3→import { ESCROW_ABI } from '@clawquest/shared';
  4→import { escrowConfig, isEscrowConfigured, getContractAddress, isChainAllowed } from './escrow.config';
  5→import { getPublicClient } from './escrow.client';
  6→import {
  7→    handleQuestFunded,
  8→    handleQuestDistributed,
  9→    handleQuestRefunded,
 10→    handleEmergencyWithdrawal,
 11→} from './escrow-event-handlers';
 12→import {
 13→    notifyQuestFunded,
 14→    notifyQuestDistributed,
 15→    notifyQuestRefunded,
 16→} from '../telegram/services/bot-notification.service';
 17→import { bytes32ToUuid } from '@clawquest/shared';
 18→
 19→// ─── Escrow Event Poller ─────────────────────────────────────────────────────
 20→// Polls ALL active chains for escrow events and updates the database.
 21→// Uses DB-persisted cursor so restarts resume without gaps or re-scans.
 22→
 23→/** Max block range per getLogs call (RPC rate-limit safety) */
 24→const MAX_RANGE = 2000n;
 25→
 26→interface ChainHealth {
 27→    lastPollAt: Date | null;
 28→    lastError: string | null;
 29→    eventsProcessed: number;
 30→}
 31→
 32→/** Health state — exported for /escrow/health endpoint */
 33→export const escrowPollerHealth = {
 34→    running: false,
 35→    lastPollAt: null as Date | null,
 36→    lastError: null as string | null,
 37→    eventsProcessed: 0,
 38→    chains: {} as Record<number, ChainHealth>,
 39→};
 40→
 41→/** Per-chain lock: if true, that chain is currently being polled (skip next tick until done) */
 42→const chainPollInProgress: Record<number, boolean> = {};
 43→
 44→/** Initialize per-chain health entries */
 45→function initChainHealth(chainIds: number[]): void {
 46→    for (const id of chainIds) {
 47→        escrowPollerHealth.chains[id] = {
 48→            lastPollAt: null,
 49→            lastError: null,
 50→            eventsProcessed: 0,
 51→        };
 52→        chainPollInProgress[id] = false;
 53→    }
 54→}
 55→
 56→/** Read persisted cursor from DB, or default to recent blocks on first run */
 57→async function getCursor(server: FastifyInstance, chainId: number, currentBlock: bigint): Promise<bigint> {
 58→    try {
 59→        const row = await server.prisma.escrowCursor.findUnique({ where: { chainId } });
 60→        if (row) {
 61→            server.log.debug(`[escrow:poller] chain ${chainId} cursor from DB: block ${row.lastBlock}`);
 62→            return row.lastBlock;
 63→        }
 64→        server.log.info(`[escrow:poller] chain ${chainId} no cursor in DB — first run, starting from block ${currentBlock - 100n}`);
 65→    } catch (err: any) {
 66→        // Table may not exist yet (migration pending) — fall through to default
 67→        server.log.warn(`[escrow:poller] EscrowCursor table not available (${err.message}), using default cursor`);
 68→    }
 69→    // First run: start from last ~100 blocks to catch recent events
 70→    return currentBlock > 100n ? currentBlock - 100n : 0n;
 71→}
 72→
 73→/** Persist the last processed block for a chain */
 74→async function saveCursor(server: FastifyInstance, chainId: number, lastBlock: bigint): Promise<void> {
 75→    try {
 76→        await server.prisma.escrowCursor.upsert({
 77→            where: { chainId },
 78→            create: { chainId, lastBlock },
 79→            update: { lastBlock },
 80→        });
 81→    } catch {
 82→        // Table may not exist yet — skip persisting, will re-scan on next poll
 83→        server.log.warn('[escrow:poller] Failed to save cursor (migration pending?)');
 84→    }
 85→}
 86→
 87→/**
 88→ * Poll for all escrow events on a specific chain.
 89→ * Uses confirmation buffer to avoid processing re-org'd blocks.
 90→ */
 91→async function pollChain(server: FastifyInstance, chainId: number): Promise<void> {
 92→    const client = getPublicClient(chainId);
 93→    const chainHealth = escrowPollerHealth.chains[chainId];
 94→    if (chainPollInProgress[chainId]) return;
 95→
 96→    chainPollInProgress[chainId] = true;
 97→    try {
 98→        const currentBlock = await client.getBlockNumber();
 99→        // Safe block = tip minus confirmation buffer (re-org protection)
100→        const safeBlock = currentBlock > BigInt(escrowConfig.confirmationBlocks)
101→            ? currentBlock - BigInt(escrowConfig.confirmationBlocks)
102→            : currentBlock;
103→
104→        const cursorBlock = await getCursor(server, chainId, currentBlock);
105→        const fromBlock = cursorBlock + 1n;
106→
107→        // No new safe blocks to process
108→        if (fromBlock > safeBlock) return;
109→
110→        // Cap range to avoid RPC rate limits
111→        const toBlock = fromBlock + MAX_RANGE - 1n < safeBlock
112→            ? fromBlock + MAX_RANGE - 1n
113→            : safeBlock;
114→
115→        // Fetch all escrow event logs in one call
116→        const rawLogs = await client.getLogs({
117→            address: getContractAddress(chainId),
118→            fromBlock,
119→            toBlock,
120→        });
121→
122→        if (rawLogs.length === 0) {
123→            server.log.info(`[escrow:poller] Saving1 cursor for chain ${chainId} to block ${toBlock}`);
124→            await saveCursor(server, chainId, toBlock);
125→            if (chainHealth) {
126→                chainHealth.lastPollAt = new Date();
127→                chainHealth.lastError = null;
128→            }
129→            chainPollInProgress[chainId] = false;
130→            return;
131→        }
132→
133→        // Decode logs using the full ABI — unknown events are filtered out
134→        const events = parseEventLogs({ abi: ESCROW_ABI, logs: rawLogs });
135→        let processed = 0;
136→
137→        for (const event of events) {
138→            const txHash = event.transactionHash;
139→            if (!txHash) continue;
140→
141→            try {
142→                switch (event.eventName) {
143→                    case 'QuestFunded': {
144→                        const { questId, sponsor, token, amount, expiresAt } = event.args as any;
145→                        await handleQuestFunded(server.prisma, questId, sponsor, token, BigInt(amount), BigInt(expiresAt), txHash, chainId);
146→                        notifyQuestFunded(server, bytes32ToUuid(questId)).catch(() => { });
147→                        break;
148→                    }
149→                    case 'QuestDistributed': {
150→                        const { questId, recipients, amounts, totalPayout } = event.args as any;
151→                        await handleQuestDistributed(server.prisma, questId, recipients, amounts.map(BigInt), BigInt(totalPayout), txHash, chainId);
152→                        notifyQuestDistributed(server, bytes32ToUuid(questId)).catch(() => { });
153→                        break;
154→                    }
155→                    case 'QuestRefunded': {
156→                        const { questId, sponsor, amount } = event.args as any;
157→                        await handleQuestRefunded(server.prisma, questId, sponsor, BigInt(amount), txHash, chainId);
158→                        notifyQuestRefunded(server, bytes32ToUuid(questId)).catch(() => { });
159→                        break;
160→                    }
161→                    case 'EmergencyWithdrawal': {
162→                        const { questId, sponsor, amount } = event.args as any;
163→                        await handleEmergencyWithdrawal(server.prisma, questId, sponsor, BigInt(amount), txHash, chainId);
164→                        notifyQuestRefunded(server, bytes32ToUuid(questId)).catch(() => { });
165→                        break;
166→                    }
167→                    default:
168→                        continue; // skip non-quest events (Paused, TokenAllowlist, etc.)
169→                }
170→                processed++;
171→            } catch (err: any) {
172→                server.log.error({ err, eventName: event.eventName, txHash }, '[escrow:poller] Error handling event');
173→            }
174→        }
175→
176→        if (processed > 0) {
177→            server.log.info(`[escrow:poller] Processed ${processed} events on chain ${chainId} (blocks ${fromBlock}-${toBlock})`);
178→            escrowPollerHealth.eventsProcessed += processed;
179→            if (chainHealth) chainHealth.eventsProcessed += processed;
180→        }
181→        server.log.info(`[escrow:poller] Saving2 cursor for chain ${chainId} to block ${toBlock}`);
182→
183→        await saveCursor(server, chainId, toBlock);
184→
185→        const now = new Date();
186→        escrowPollerHealth.lastPollAt = now;
187→        escrowPollerHealth.lastError = null;
188→        if (chainHealth) {
189→            chainHealth.lastPollAt = now;
190→            chainHealth.lastError = null;
191→        }
192→    } catch (err: any) {
193→        escrowPollerHealth.lastError = `chain ${chainId}: ${err.message}`;
194→        if (chainHealth) chainHealth.lastError = err.message;
195→        server.log.error({ err, chainId }, '[escrow:poller] Error polling chain');
196→    } finally {
197→        chainPollInProgress[chainId] = false;
198→    }
199→}
200→
201→/**
202→ * Poll all active chains in parallel.
203→ * Uses Promise.allSettled so one chain failing doesn't block others.
204→ */
205→async function pollAllChains(server: FastifyInstance, chainIds: number[]): Promise<void> {
206→    server.log.info(`[escrow:poller] Tick — polling chains [${chainIds.join(', ')}]`);
207→    await Promise.allSettled(
208→        chainIds.map(chainId => pollChain(server, chainId))
209→    );
210→}
211→
212→/**
213→ * Start the escrow event poller.
214→ * Polls ALL active chains for escrow events at a regular interval.
215→ */
216→export async function startEscrowPoller(server: FastifyInstance): Promise<void> {
217→    if (!isEscrowConfigured()) {
218→        server.log.warn('[escrow:poller] Escrow not configured — skipping poller');
219→        return;
220→    }
221→
222→    // Filter activeChainIds to only chains allowed in current networkMode
223→    const chainIds = escrowConfig.activeChainIds.filter(id => isChainAllowed(id));
224→    if (chainIds.length === 0) {
225→        server.log.warn('[escrow:poller] No active chains to poll');
226→        return;
227→    }
228→
229→    server.log.info(
230→        `[escrow:poller] Starting for chains [${chainIds.join(', ')}] ` +
231→        `(interval: ${escrowConfig.pollingIntervalMs}ms, confirmations: ${escrowConfig.confirmationBlocks})`
232→    );
233→
234→    initChainHealth(chainIds);
235→    escrowPollerHealth.running = true;
236→    let interval: NodeJS.Timeout | undefined;
237→
238→    server.addHook('onClose', () => {
239→        escrowPollerHealth.running = false;
240→        if (interval) clearInterval(interval);
241→        server.log.info('[escrow:poller] Stopped');
242→    });
243→
244→    // Initial poll
245→    await pollAllChains(server, chainIds);
246→
247→    interval = setInterval(async () => {
248→        await pollAllChains(server, chainIds);
249→    }, escrowConfig.pollingIntervalMs);
250→}
