 1→import { Hono } from 'hono';
 2→import type { Env, ApiKey } from '../types';
 3→import { sha256, requireApiKey } from '../middleware/auth';
 4→import { createApiKey, getTokenUsage } from '../db/queries';
 5→
 6→const keys = new Hono<{ Bindings: Env; Variables: { apiKey: ApiKey } }>();
 7→
 8→/** POST /api/v1/keys — create a new API key (authenticated with SECRET_KEY) */
 9→keys.post('/api/v1/keys', async (c) => {
10→  const body = await c.req.json<{ secret_key: string; name?: string; max_token_usage?: number }>();
11→
12→  if (!body.secret_key || body.secret_key !== c.env.SECRET_KEY) {
13→    return c.json({ detail: 'Invalid secret key' }, 401);
14→  }
15→
16→  // Generate sk-{64 random chars}
17→  const raw = `${crypto.randomUUID().replace(/-/g, '')}${crypto.randomUUID().replace(/-/g, '')}`;
18→  const apiKeyValue = `sk-${raw}`;
19→  const apiKeyHash = await sha256(apiKeyValue);
20→
21→  const record = await createApiKey(c.env.DB, apiKeyValue, apiKeyHash, body.name ?? null, body.max_token_usage);
22→
23→  return c.json({
24→    api_key: record.api_key,
25→    name: record.name,
26→    max_token_usage: record.max_token_usage,
27→    created_at: record.created_at,
28→    message: 'API key created successfully. Save this key as it won\'t be shown again.',
29→  });
30→});
31→
32→/** GET /api/v1/keys/usage — get token usage for the authenticated key */
33→keys.get('/api/v1/keys/usage', requireApiKey, async (c) => {
34→  const apiKey = c.var.apiKey;
35→  const usage = await getTokenUsage(c.env.DB, apiKey.id);
36→
37→  return c.json({
38→    api_key_id: apiKey.id,
39→    name: apiKey.name,
40→    is_active: apiKey.is_active === 1,
41→    max_token_usage: apiKey.max_token_usage,
42→    tokens_in: usage?.tokens_in ?? 0,
43→    tokens_out: usage?.tokens_out ?? 0,
44→    total_tokens: (usage?.tokens_in ?? 0) + (usage?.tokens_out ?? 0),
45→    request_count: usage?.request_count ?? 0,
46→    last_used_at: usage?.last_used_at ?? null,
47→  });
48→});
49→
50→export default keys;
51→

  1→import { FastifyInstance } from 'fastify';
  2→import { ZodTypeProvider } from 'fastify-type-provider-zod';
  3→import { AgentSchema } from '@clawquest/shared';
  4→import { z } from 'zod';
  5→import { authenticateAgent } from './agent-auth.helper';
  6→
  7→// ─── Routes ──────────────────────────────────────────────────────────────────
  8→
  9→export async function agentsRoutes(app: FastifyInstance) {
 10→    const server = app.withTypeProvider<ZodTypeProvider>();
 11→
 12→    // ── List Agents (human JWT) ───────────────────────────────────────────────
 13→    server.get(
 14→        '/',
 15→        {
 16→            onRequest: [app.authenticate],
 17→            schema: {
 18→                tags: ['Agents'],
 19→                summary: 'List user agents',
 20→                security: [{ bearerAuth: [] }],
 21→                response: { 200: z.array(AgentSchema) },
 22→            },
 23→        },
 24→        async (request) => {
 25→            const agents = await server.prisma.agent.findMany({
 26→                where: { ownerId: request.user.id },
 27→                orderBy: { createdAt: 'desc' },
 28→            });
 29→            return agents.map(a => ({
 30→                id: a.id,
 31→                agentname: a.agentname,
 32→                status: a.status as any,
 33→                ownerId: a.ownerId,
 34→                isActive: a.isActive,
 35→                agentApiKey: a.agentApiKey ?? undefined,
 36→                createdAt: a.createdAt.toISOString(),
 37→                updatedAt: a.updatedAt.toISOString(),
 38→            }));
 39→        }
 40→    );
 41→
 42→    // ── Get Agent Details (human JWT) ─────────────────────────────────────────
 43→    server.get(
 44→        '/:id',
 45→        {
 46→            onRequest: [app.authenticate],
 47→            schema: {
 48→                tags: ['Agents'],
 49→                summary: 'Get agent details',
 50→                security: [{ bearerAuth: [] }],
 51→                params: z.object({ id: z.string().uuid() }),
 52→                response: { 200: AgentSchema },
 53→            },
 54→        },
 55→        async (request, reply) => {
 56→            const { id } = request.params as { id: string };
 57→            const agent = await server.prisma.agent.findFirst({
 58→                where: { id, ownerId: request.user.id },
 59→            });
 60→            if (!agent) {
 61→                return reply.status(404).send({ message: 'Agent not found', code: 'NOT_FOUND' } as any);
 62→            }
 63→            return {
 64→                id: agent.id,
 65→                agentname: agent.agentname,
 66→                status: agent.status as any,
 67→                ownerId: agent.ownerId,
 68→                isActive: agent.isActive,
 69→                agentApiKey: agent.agentApiKey ?? undefined,
 70→                createdAt: agent.createdAt.toISOString(),
 71→                updatedAt: agent.updatedAt.toISOString(),
 72→            };
 73→        }
 74→    );
 75→
 76→    // ── PATCH /agents/:id/activate — set agent as active (human JWT) ──────────
 77→    server.patch(
 78→        '/:id/activate',
 79→        {
 80→            onRequest: [app.authenticate],
 81→            schema: {
 82→                tags: ['Agents'],
 83→                summary: 'Set agent as active — only this agent can call questing APIs',
 84→                security: [{ bearerAuth: [] }],
 85→                params: z.object({ id: z.string().uuid() }),
 86→                response: {
 87→                    200: z.object({ agentId: z.string(), isActive: z.boolean(), message: z.string() }),
 88→                },
 89→            },
 90→        },
 91→        async (request, reply) => {
 92→            const { id } = request.params as { id: string };
 93→            const userId = (request as any).user.id;
 94→
 95→            // Verify ownership
 96→            const agent = await server.prisma.agent.findFirst({
 97→                where: { id, ownerId: userId },
 98→                select: { id: true, agentname: true },
 99→            });
100→            if (!agent) return reply.status(404).send({ error: 'Agent not found or not owned by you' } as any);
101→
102→            // Deactivate all other agents for this user, then activate this one
103→            await server.prisma.$transaction([
104→                server.prisma.agent.updateMany({
105→                    where: { ownerId: userId, isActive: true },
106→                    data: { isActive: false },
107→                }),
108→                server.prisma.agent.update({
109→                    where: { id },
110→                    data: { isActive: true },
111→                }),
112→            ]);
113→
114→            return { agentId: id, isActive: true, message: `Agent "${agent.agentname}" is now active.` };
115→        }
116→    );
117→
118→    // ── DELETE /agents/:id — delete agent (human JWT) ─────────────────────────
119→    server.delete(
120→        '/:id',
121→        {
122→            onRequest: [app.authenticate],
123→            schema: {
124→                tags: ['Agents'],
125→                summary: 'Delete an agent (only if idle or pending claim)',
126→                security: [{ bearerAuth: [] }],
127→                params: z.object({ id: z.string().uuid() }),
128→                response: {
129→                    200: z.object({ message: z.string() }),
130→                },
131→            },
132→        },
133→        async (request, reply) => {
134→            const { id } = request.params as { id: string };
135→            const userId = (request as any).user.id;
136→
137→            const agent = await server.prisma.agent.findFirst({
138→                where: { id, ownerId: userId },
139→                select: { id: true, status: true, agentname: true },
140→            });
141→            if (!agent) return reply.status(404).send({ error: 'Agent not found or not owned by you' } as any);
142→            if (agent.status === 'questing') {
143→                return reply.status(400).send({ error: 'Cannot delete an agent that is currently questing' } as any);
144→            }
145→
146→            await server.prisma.agent.delete({ where: { id } });
147→            return { message: `Agent "${agent.agentname}" deleted.` };
148→        }
149→    );
