### 3. TtlCache Usage

#### TtlCache Implementation
**File:** `/Users/vuongluu/Documents/jobs/lab3/ceo/clawquest/apps/api/src/utils/ttl-cache.ts`

Simple in-memory TTL cache with no external dependencies:

```typescript
export class TtlCache<T> {
    private store = new Map<string, CacheEntry<T>>();
    private interval: NodeJS.Timeout;

    constructor(cleanupIntervalMs = 5 * 60_000) {
        // Default cleanup: 5 minutes. Timer unrefs to not block process exit
        this.interval = setInterval(() => this.cleanup(), cleanupIntervalMs);
        this.interval.unref();
    }

    get(key: string): T | undefined {
        const entry = this.store.get(key);
        if (!entry) return undefined;
        if (Date.now() > entry.expiresAt) {
            this.store.delete(key);
            return undefined;
        }
        return entry.data;
    }

    set(key: string, value: T, ttlMs: number): void {
        this.store.set(key, { data: value, expiresAt: Date.now() + ttlMs });
    }

    delete(key: string): void {
        this.store.delete(key);
    }

    deleteByPrefix(prefix: string): void {
        for (const key of this.store.keys()) {
            if (key.startsWith(prefix)) this.store.delete(key);
        }
    }

    destroy(): void {
        clearInterval(this.interval);  // for tests/graceful shutdown
    }
}
```

#### Actual Usage in Supabase JWT Verifier
**File:** `/Users/vuongluu/Documents/jobs/lab3/ceo/clawquest/apps/api/src/utils/supabase-jwt.ts` (lines 16-77)

The JWT verifier caches user lookups to avoid DB queries:

```typescript
const USER_CACHE_TTL_MS = 5 * 60_000; // 5 minutes

export interface SupabaseJwtVerifier {
    verifyToken(token: string): Promise<SupabaseJwtPayload>;
    getCachedUser(supabaseId: string): User | undefined;
    cacheUser(supabaseId: string, user: User): void;
}

export function createSupabaseJwtVerifier(supabaseUrl: string): SupabaseJwtVerifier {
    const userCache = new Map<string, UserCacheEntry>();

    return {
        getCachedUser(supabaseId: string): User | undefined {
            const entry = userCache.get(supabaseId);
            if (!entry) return undefined;
            if (Date.now() - entry.cachedAt > USER_CACHE_TTL_MS) {
                userCache.delete(supabaseId);
                return undefined;
            }
            return entry.user;
        },

        cacheUser(supabaseId: string, user: User): void {
            userCache.set(supabaseId, { user, cachedAt: Date.now() });
        },
    };
}
```

**Usage in app.ts (lines 167-221):**
