### 4. Auth Middleware

#### Two Auth Flows

**Flow 1: Human JWT (Supabase)**
- Frontend sends: `Authorization: Bearer <supabase-access-token>`
- Verify via local JWT (no network call) using JWKS
- Fallback to Supabase HTTP API if JWKS verification fails
- Find/create local Prisma User from supabaseId

**Flow 2: Agent API Key**
- Agents send: `Authorization: Bearer cq_<api-key>`
- Custom helper checks `Agent.agentApiKey` in DB
- Only for specific agent endpoints (e.g., GET `/agents/me`)

#### Middleware Implementation
**File:** `/Users/vuongluu/Documents/jobs/lab3/ceo/clawquest/apps/api/src/app.ts` (lines 110-231)

```typescript
server.decorate('authenticate', async (request: FastifyRequest, reply: FastifyReply) => {
    const authHeader = request.headers.authorization;
    if (!authHeader?.startsWith('Bearer ')) {
        return reply.status(401).send({ message: 'Missing or invalid Authorization header' });
    }

    const token = authHeader.slice(7);

    // 1. Try admin JWT first (for admin dashboard)
    const adminPayload = verifyAdminJwt(token);
    if (adminPayload) {
        request.user = { id: adminPayload.id, email: adminPayload.email, role: adminPayload.role, ... };
        return;
    }

    // 2. Local JWT verification (with jose JWKS cache)
    let supabaseId, supabaseEmail, supabaseUserMetadata;

    if (jwtVerifier) {
        try {
            const payload = await jwtVerifier.verifyToken(token);
            supabaseId = payload.sub;
            supabaseEmail = payload.email;
            supabaseUserMetadata = payload.user_metadata;
        } catch (err) {
            if (isJwtError(err)) {
                return reply.status(401).send({ message: 'Invalid or expired token' });
            }
            // Fall back to HTTP API on network/JWKS failure
            const { data, error } = await supabaseAdmin.auth.getUser(token);
            // ... handle error ...
        }
    } else {
        // No SUPABASE_URL configured — HTTP only
        const { data, error } = await supabaseAdmin.auth.getUser(token);
        // ... handle error ...
    }

    // 3. Check user cache (5-min TTL)
    const cachedUser = jwtVerifier?.getCachedUser(supabaseId);
    if (cachedUser) {
        request.user = { id: cachedUser.id, email: cachedUser.email, ... };
        return;
    }

    // 4. Find or create Prisma user
    let user = await server.prisma.user.findUnique({ where: { supabaseId } });

    if (!user) {
        // Also check by email (legacy seeded users)
        user = await server.prisma.user.findUnique({ where: { email: supabaseEmail } });

        if (user) {
            // Link to Supabase
            user = await server.prisma.user.update({
                where: { id: user.id },
                data: { supabaseId },
            });
        } else {
            // Create new user
            const fullName = (supabaseUserMetadata?.full_name as string) || null;
            user = await server.prisma.user.create({
                data: { supabaseId, email: supabaseEmail, displayName: fullName },
            });
        }
    }

    // Sync displayName from metadata
    if (!user.displayName && supabaseUserMetadata?.full_name) {
        user = await server.prisma.user.update({
            where: { id: user.id },
            data: { displayName: supabaseUserMetadata.full_name },
        });
    }

    // Cache for 5 minutes
    jwtVerifier?.cacheUser(supabaseId, user);

    request.user = {
        id: user.id,
        email: user.email,
        username: user.username,
        displayName: user.displayName,
        supabaseId,
        role: user.role ?? 'user',
    };
});
```

#### Agent Auth Helper
**File:** `/Users/vuongluu/Documents/jobs/lab3/ceo/clawquest/apps/api/src/modules/agents/agent-auth.helper.ts`

```typescript
export async function authenticateAgent(
    server: FastifyInstance & { prisma: any },
    request: FastifyRequest,
    reply: FastifyReply
): Promise<{ agentId: string; ownerId: string | null } | null | undefined> {
    const auth = request.headers.authorization;
    if (!auth?.startsWith('Bearer cq_')) {
        reply.status(401).send({ error: 'Missing or invalid agent API key' });
        return null;
    }
    const apiKey = auth.slice(7);
    const agent = await server.prisma.agent.findUnique({
        where: { agentApiKey: apiKey },
        select: { id: true, ownerId: true },
    });
    if (!agent) {
        reply.status(401).send({ error: 'Invalid agent API key' });
        return null;
    }
    return { agentId: agent.id, ownerId: agent.ownerId };
}
```

