106→// ─── Supabase Auth Middleware ────────────────────────────────────────────────
107→// Verifies the Supabase access_token sent by the frontend,
108→// then finds-or-creates a Prisma User row so route handlers get `request.user.id`.
109→
110→server.decorate('authenticate', async (request: FastifyRequest, reply: FastifyReply) => {
111→    const authHeader = request.headers.authorization;
112→    if (!authHeader?.startsWith('Bearer ')) {
113→        return reply.status(401).send({ message: 'Missing or invalid Authorization header' });
114→    }
115→
116→    const token = authHeader.slice(7);
117→
118→    // ── Try admin JWT first (admin dashboard tokens) ──────────────────────────
119→    const adminPayload = verifyAdminJwt(token);
120→    if (adminPayload) {
121→        request.user = {
122→            id: adminPayload.id,
123→            email: adminPayload.email,
124→            role: adminPayload.role,
125→            username: null,
126→            displayName: null,
127→            supabaseId: '',
128→        };
129→        return;
130→    }
131→
132→    // ── Local JWT verification (no network call) ──────────────────────────────
133→    let supabaseId: string;
134→    let supabaseEmail: string;
135→    let supabaseUserMetadata: Record<string, unknown> = {};
136→
137→    if (jwtVerifier) {
138→        try {
139→            const payload = await jwtVerifier.verifyToken(token);
140→            supabaseId = payload.sub;
141→            supabaseEmail = payload.email;
142→            supabaseUserMetadata = payload.user_metadata;
143→        } catch (err) {
144→            if (isJwtError(err)) {
145→                return reply.status(401).send({ message: 'Invalid or expired token' });
146→            }
147→            // Network/JWKS failure — fall back to Supabase HTTP API
148→            const { data, error } = await supabaseAdmin.auth.getUser(token);
149→            if (error || !data.user) {
150→                return reply.status(401).send({ message: 'Invalid or expired token' });
151→            }
152→            supabaseId = data.user.id;
153→            supabaseEmail = data.user.email!;
154→            supabaseUserMetadata = data.user.user_metadata ?? {};
155→        }
156→    } else {
157→        // No SUPABASE_URL configured — fall back to HTTP (dev without env vars)
158→        const { data, error } = await supabaseAdmin.auth.getUser(token);
159→        if (error || !data.user) {
160→            return reply.status(401).send({ message: 'Invalid or expired token' });
161→        }
162→        supabaseId = data.user.id;
163→        supabaseEmail = data.user.email!;
164→        supabaseUserMetadata = data.user.user_metadata ?? {};
165→    }
166→
167→    // ── Check user cache before DB lookup ─────────────────────────────────────
168→    const cachedUser = jwtVerifier?.getCachedUser(supabaseId);
169→    if (cachedUser) {
170→        request.user = {
171→            id: cachedUser.id,
172→            email: cachedUser.email,
173→            username: cachedUser.username,
174→            displayName: cachedUser.displayName,
175→            supabaseId,
176→            role: cachedUser.role ?? 'user',
177→        };
178→        return;
179→    }
180→
181→    // ── Find or create local Prisma user ──────────────────────────────────────
182→    let user = await server.prisma.user.findUnique({
183→        where: { supabaseId },
184→    });
185→
186→    if (!user) {
187→        // Also check by email (for legacy seeded users)
188→        user = await server.prisma.user.findUnique({
189→            where: { email: supabaseEmail },
190→        });
191→
192→        if (user) {
193→            // Link existing user to Supabase
194→            user = await server.prisma.user.update({
195→                where: { id: user.id },
196→                data: { supabaseId },
197→            });
198→        } else {
199→            // Create new Prisma user
200→            const fullName = (supabaseUserMetadata?.full_name as string) || null;
201→            user = await server.prisma.user.create({
202→                data: {
203→                    supabaseId,
204→                    email: supabaseEmail,
205→                    displayName: fullName,
206→                },
207→            });
208→        }
209→    }
210→
211→    // Sync displayName from metadata if not yet set
212→    const metaFullName = (supabaseUserMetadata?.full_name as string) || null;
213→    if (!user.displayName && metaFullName) {
214→        user = await server.prisma.user.update({
215→            where: { id: user.id },
216→            data: { displayName: metaFullName },
217→        });
218→    }
219→
220→    // Cache user for subsequent requests (5-min TTL)
221→    jwtVerifier?.cacheUser(supabaseId, user);
222→
223→    request.user = {
224→        id: user.id,
225→        email: user.email,
226→        username: user.username,
227→        displayName: user.displayName,
228→        supabaseId,
229→        role: user.role ?? 'user',
230→    };
