  1→import { FastifyInstance } from 'fastify';
  2→import { z } from 'zod';
  3→
  4→const WALLET_ADDRESS_RE = /^0x[a-fA-F0-9]{40}$/;
  5→
  6→const WalletSchema = z.object({
  7→    id: z.string(),
  8→    address: z.string(),
  9→    chainId: z.number().nullable(),
 10→    isPrimary: z.boolean(),
 11→    createdAt: z.string(),
 12→});
 13→
 14→export async function walletsRoutes(server: FastifyInstance) {
 15→    // ─── POST /wallets — Link a wallet to user ────────────────────────────────
 16→    server.post(
 17→        '/',
 18→        {
 19→            onRequest: [server.authenticate],
 20→            schema: {
 21→                tags: ['Wallets'],
 22→                summary: 'Link a wallet address to the authenticated user',
 23→                security: [{ bearerAuth: [] }],
 24→                body: z.object({
 25→                    address: z.string().regex(WALLET_ADDRESS_RE, 'Invalid wallet address'),
 26→                    chainId: z.number().int().optional(),
 27→                }),
 28→                response: { 200: WalletSchema },
 29→            },
 30→        },
 31→        async (request) => {
 32→            const userId = request.user.id;
 33→            const { address, chainId } = request.body as { address: string; chainId?: number };
 34→
 35→            // Normalize address to lowercase for consistent comparison
 36→            const normalizedAddress = address.toLowerCase();
 37→
 38→            // First wallet becomes primary
 39→            const existingCount = await server.prisma.walletLink.count({ where: { userId } });
 40→
 41→            const wallet = await server.prisma.walletLink.upsert({
 42→                where: { userId_address: { userId, address: normalizedAddress } },
 43→                update: { chainId: chainId ?? undefined },
 44→                create: {
 45→                    userId,
 46→                    address: normalizedAddress,
 47→                    chainId: chainId ?? null,
 48→                    isPrimary: existingCount === 0,
 49→                },
 50→            });
 51→
 52→            return {
 53→                id: wallet.id,
 54→                address: wallet.address,
 55→                chainId: wallet.chainId,
 56→                isPrimary: wallet.isPrimary,
 57→                createdAt: wallet.createdAt.toISOString(),
 58→            };
 59→        }
 60→    );
 61→
 62→    // ─── GET /wallets — List user's wallets ───────────────────────────────────
 63→    server.get(
 64→        '/',
 65→        {
 66→            onRequest: [server.authenticate],
 67→            schema: {
 68→                tags: ['Wallets'],
 69→                summary: 'List wallets linked to the authenticated user',
 70→                security: [{ bearerAuth: [] }],
 71→                response: { 200: z.array(WalletSchema) },
 72→            },
 73→        },
 74→        async (request) => {
 75→            const userId = request.user.id;
 76→
 77→            const wallets = await server.prisma.walletLink.findMany({
 78→                where: { userId },
 79→                orderBy: [{ isPrimary: 'desc' }, { createdAt: 'asc' }],
 80→            });
 81→
 82→            return wallets.map(w => ({
 83→                id: w.id,
 84→                address: w.address,
 85→                chainId: w.chainId,
 86→                isPrimary: w.isPrimary,
 87→                createdAt: w.createdAt.toISOString(),
 88→            }));
 89→        }
 90→    );
 91→
 92→    // ─── DELETE /wallets/:id — Remove a wallet ────────────────────────────────
 93→    server.delete(
 94→        '/:id',
 95→        {
 96→            onRequest: [server.authenticate],
 97→            schema: {
 98→                tags: ['Wallets'],
 99→                summary: 'Remove a linked wallet',
100→                security: [{ bearerAuth: [] }],
101→                params: z.object({ id: z.string() }),
102→                response: { 200: z.object({ ok: z.boolean() }) },
103→            },
104→        },
105→        async (request, reply) => {
106→            const userId = request.user.id;
107→            const { id } = request.params as { id: string };
108→
109→            const wallet = await server.prisma.walletLink.findUnique({ where: { id } });
110→            if (!wallet || wallet.userId !== userId) {
111→                return reply.status(404).send({ error: { message: 'Wallet not found', code: 'WALLET_NOT_FOUND' } });
112→            }
113→
114→            await server.prisma.walletLink.delete({ where: { id } });
115→
116→            // If deleted wallet was primary, promote the oldest remaining wallet
117→            if (wallet.isPrimary) {
118→                const next = await server.prisma.walletLink.findFirst({
119→                    where: { userId },
120→                    orderBy: { createdAt: 'asc' },
121→                });
122→                if (next) {
123→                    await server.prisma.walletLink.update({
124→                        where: { id: next.id },
125→                        data: { isPrimary: true },
126→                    });
127→                }
128→            }
129→
130→            return { ok: true };
131→        }
132→    );
133→
134→    // ─── PATCH /wallets/:id/primary — Set wallet as primary ──────────────────
135→    server.patch(
136→        '/:id/primary',
137→        {
138→            onRequest: [server.authenticate],
139→            schema: {
140→                tags: ['Wallets'],
141→                summary: 'Set a wallet as the primary wallet',
142→                security: [{ bearerAuth: [] }],
143→                params: z.object({ id: z.string() }),
144→                response: { 200: WalletSchema },
145→            },
146→        },
147→        async (request, reply) => {
148→            const userId = request.user.id;
149→            const { id } = request.params as { id: string };
150→
151→            const wallet = await server.prisma.walletLink.findUnique({ where: { id } });
152→            if (!wallet || wallet.userId !== userId) {
153→                return reply.status(404).send({ error: { message: 'Wallet not found', code: 'WALLET_NOT_FOUND' } });
154→            }
155→
156→            // Transaction: clear all primary flags → set this one
157→            const [, updated] = await server.prisma.$transaction([
158→                server.prisma.walletLink.updateMany({
159→                    where: { userId, isPrimary: true },
160→                    data: { isPrimary: false },
161→                }),
162→                server.prisma.walletLink.update({
163→                    where: { id },
164→                    data: { isPrimary: true },
165→                }),
166→            ]);
167→
168→            return {
169→                id: updated.id,
170→                address: updated.address,
171→                chainId: updated.chainId,
172→                isPrimary: updated.isPrimary,
173→                createdAt: updated.createdAt.toISOString(),
174→            };
175→        }
176→    );
177→}
