 12→/**
 13→ * Handle Telegram OIDC login: exchange code, verify JWT, find/create user, generate Supabase session.
 14→ */
 15→export async function handleTelegramLogin(params: {
 16→    code: string;
 17→    codeVerifier: string;
 18→    redirectUri: string;
 19→    prisma: PrismaClient;
 20→    supabaseAdmin: SupabaseClient;
 21→}): Promise<TelegramLoginResult> {
 22→    const { code, codeVerifier, redirectUri, prisma, supabaseAdmin } = params;
 23→
 24→    // 1. Exchange code for tokens
 25→    const tokens = await exchangeTelegramCode({ code, codeVerifier, redirectUri });
 26→
 27→    // 2. Verify ID token
 28→    const claims = await verifyTelegramIdToken(tokens.id_token);
 29→    const telegramId = claims.telegramId; // string — safe for IDs beyond PG bigint range
 30→    const placeholderEmail = `tg_${telegramId}@tg.clawquest.ai`;
 31→
 32→    // 3. Find existing user by telegramId (normal Prisma query — column is now TEXT)
 33→    let user = await prisma.user.findUnique({ where: { telegramId } });
 34→    let isNewUser = false;
 35→
 36→    if (!user) {
 37→        isNewUser = true;
 38→
 39→        // Create Supabase auth user with placeholder email
 40→        const { data: supabaseUser, error: createError } = await supabaseAdmin.auth.admin.createUser({
 41→            email: placeholderEmail,
 42→            email_confirm: true,
 43→            user_metadata: {
 44→                telegramId: claims.telegramId,
 45→                telegram_username: claims.username,
 46→                provider: 'telegram',
 47→                full_name: claims.name,
 48→                avatar_url: claims.picture,
 49→            },
 50→        });
 51→
 52→        if (createError) {
 53→            // User might already exist in Supabase (e.g. from a previous failed attempt)
 54→            if (createError.message?.includes('already been registered')) {
 55→                // Generate a session directly — the Supabase user exists, just missing Prisma row
 56→                const session = await generateSupabaseSession(supabaseAdmin, placeholderEmail);
 57→
 58→                // Get the Supabase user ID from the session token
 59→                const { data: sessionUser } = await supabaseAdmin.auth.getUser(session.access_token);
 60→                if (!sessionUser?.user) {
 61→                    throw new Error('Supabase user exists but session verification failed');
 62→                }
 63→
 64→                // Upsert Prisma user to handle race conditions
 65→                user = await prisma.user.upsert({
 66→                    where: { telegramId },
 67→                    update: { supabaseId: sessionUser.user.id },
 68→                    create: {
 69→                        supabaseId: sessionUser.user.id,
 70→                        email: placeholderEmail,
 71→                        username: claims.username ?? `tg_${claims.telegramId}`,
 72→                        displayName: claims.name ?? null,
 73→                        telegramId,
 74→                        telegramUsername: claims.username ?? null,
 75→                    },
 76→                });
 77→
 78→                // Short-circuit: we already have the session
 79→                const linkedAgents = await autoLinkAgents(prisma, telegramId, user.id);
 80→                await linkWaitlistEntry(prisma, telegramId, user.id);
 81→                return {
 82→                    session,
 83→                    user: {
 84→                        id: user.id,
 85→                        email: user.email,
 86→                        username: user.username,
 87→                        telegramId: user.telegramId!,
 88→                        telegramUsername: user.telegramUsername,
 89→                    },
 90→                    isNewUser: true,
 91→                    linkedAgents,
 92→                };
 93→            } else {
 94→                throw new Error(`Failed to create Supabase user: ${createError.message}`);
 95→            }
 96→        } else {
 97→            // Upsert Prisma user to handle concurrent first-login race
