103→                    email: placeholderEmail,
104→                    username: claims.username ?? `tg_${claims.telegramId}`,
105→                    displayName: claims.name ?? null,
106→                    telegramId,
107→                    telegramUsername: claims.username ?? null,
108→                },
109→            });
110→        }
111→    } else {
112→        // Update username if changed
113→        if (claims.username && claims.username !== user.telegramUsername) {
114→            user = await prisma.user.update({
115→                where: { id: user.id },
116→                data: { telegramUsername: claims.username },
117→            });
118→        }
119→    }
120→
121→    // 4. Auto-link agents via TelegramLink matching (TelegramLink.telegramId is still BigInt)
122→    const linkedAgents = await autoLinkAgents(prisma, telegramId, user.id);
