```

### Step 2: Create Zod schemas

Create `/Users/vuongluu/Documents/jobs/lab3/ceo/clawquest/apps/api/src/modules/onchain/onchain.schemas.ts`:

```typescript
import { z } from 'zod';

// ─── Request schemas ────────────────────────────────────────────────────────

export const walletPortfolioQuerySchema = z.object({
    address: z.string().min(1, 'Wallet address required'),
