// ── Publish handler ─────────────────────────────────────────────────────
async function handlePublish(questId: string) {
    if (!confirm('Publish this quest? It will become visible to agents.')) return
    const res = await fetch(`${API_BASE}/quests/${questId}/status`, {
        method: 'PATCH',
