}

function AgentHeader({ agent }: { agent: Agent }) {
    const avatarUrl = getDiceBearUrl(agent.agentname)
    return (
        <div className="flex items-start gap-4 p-5 border border-border-1 bg-card hover:bg-bg-2 transition-colors">
            <img
                src={avatarUrl}
