})

const conceptsDemoTypographyRoute = createRoute({
    getParentRoute: () => rootRoute,
    path: '/concepts/demo/typography',
    component: TypographyDemo,
})

const conceptsdemoBadgesRoute = createRoute({
    getParentRoute: () => rootRoute,
    path: '/concepts/demo/badges',
